import Foundation

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: URL {
        switch self {
        case .development:
            return URL(string: "https://api.example.com/development")!
        case .staging:
            return URL(string: "https://api.example.com/staging")!
        case .production:
            return URL(string: "https://api.example.com")!
        }
    }
}

class NetworkManager {
    
    static let shared = NetworkManager()
    
    private init() {}
    
    func fetchUserData(with environment: Environment, completion: @escaping (Result<UserData, Error>) -> Void) {
        var request = URLRequest(url: environment.baseURL.appendingPathComponent("user"))
        request.httpMethod = "GET"
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NSError(domain: "", code: -1, userInfo: [NSLocalizedDescriptionKey: "No data received"])))
                return
            }
            
            do {
                let userData = try JSONDecoder().decode(UserData.self, from: data)
                completion(.success(userData))
            } catch {
                completion(.failure(error))
            }
        }
        
        task.resume()
    }
    
    func authenticateUser(username: String, password: String, with environment: Environment, completion: @escaping (Result<AuthenticationResponse, Error>) -> Void) {
        var request = URLRequest(url: environment.baseURL.appendingPathComponent("auth"))
        request.httpMethod = "POST"
        request.httpBody = try? JSONEncoder().encode(["username": username, "password": password])
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NSError(domain: "", code: -1, userInfo: [NSLocalizedDescriptionKey: "No data received"])))
                return
            }
            
            do {
                let authResponse = try JSONDecoder().decode(AuthenticationResponse.self, from: data)
                completion(.success(authResponse))
            } catch {
                completion(.failure(error))
            }
        }
        
        task.resume()
    }
}

struct UserData: Codable {
